const body = $input.first().json.body || $input.first().json;
const sid = String(body.MessageSid || body.SmsSid || body.SmsMessageSid || '').trim();
const rawStatus = String(body.MessageStatus || body.SmsStatus || body.status || '').toLowerCase().trim();
const errorCode = String(body.ErrorCode || '').trim();
const errorMessage = String(body.ErrorMessage || '').trim();
const map = {
  queued: 'queued', accepted: 'queued', scheduled: 'queued', sending: 'queued',
  sent: 'sent', delivered: 'delivered', read: 'read',
  failed: 'failed', undelivered: 'undelivered', canceled: 'failed'
};
const status = map[rawStatus] || 'sent';
return [{ json: { _message_sid: sid, _status: status, _raw_status: rawStatus, _error_code: errorCode, _error_message: errorMessage, _received_at: new Date().toISOString(), _skip: !sid } }];

